VALUES
  (
    225,
    127,
    '117',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '219.138.204.44',
    NULL,
    replace (
      '嗯，也是啊，我想的太简单了点~\n不过，网页设计看来是不能再单独出现了，要有平面设计、动画设计、程式设计（以前还可能有3D设计）等等大家一起来网页设计了~',
