INSERT INTO
  "comments"
VALUES
  (
    308,
    194,
    '133',
    NULL,
    0,
    'binbin',
    '',
    NULL,
    '61.52.91.249',
    NULL,
    replace (
      '😂 你到是提醒了我。\n我们老师以前的原文是这样：信息不是知识，更不是财富。\n信息太依赖环境，所以掌握大量信息并不是竞争的根本优势；除非这种信息是个别的，不依赖环境的。否则，别人永远都与你站在同一起跑线上。\n信息并不可靠，即便是正确的。\n呵呵……不过知识的确是一种信息，是提炼+验证了的懒惰信息。',
      '\n',
      char(10)
    ),
    'public',
    '2005-05-02T19:59:01Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    309,
    195,
    '133',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '202.103.53.18',
    NULL,
    replace (
      '嗯嗯，厉害厉害，有道理。。。\n不过，信息就是物质和能量这些产生的啊，不依赖环境的信息是什么信息呢？\n为什么说信息不可靠呢？\n懒惰信息？？？这又是怎么分出来的啊？为什么说他懒惰呢？ 😵‍💫',
      '\n',
      char(10)
    ),
    'public',
    '2005-05-02T22:43:26Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    310,
    196,
    '133',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '202.103.53.18',
    NULL,
    replace (
      '掌握大量信息并不是竞争的根本优势\n这点我也不同意，大量信息的掌握可以降低不确定性\n信息是负熵！',
