INSERT INTO
  "comments"
VALUES
  (
    317,
    222,
    '133',
    NULL,
    0,
    '暖暖鱼',
    '',
    NULL,
    '58.83.56.148',
    NULL,
    replace (
      '回关于信息是差异的问题：\n怎么说呢，差异就是一种对比，在对比之中才能显现信息价值，如果仅仅是一个事实，而没有相关的对比，你怎么确定这信息呢？我们在不断的获知过程中，其实也是在跟自己的过往经验作为基础作为对比的。\n刚刚我还看到香农对信息的定义：信息就是可以消除不确定性的东西，不是很明白，不过觉得方向不错，思考一下。',
      '\n',
      char(10)
    ),
    'public',
    '2005-05-14T22:49:43Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    318,
    223,
    '133',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '221.233.211.79',
    NULL,
    replace (
      '香农的定义是从信息应用角度来下定义的，不是很全面，他的意思是说：当你干一件事时，得到相关信息越多，就越可能干成这件事，这件事不确定性的东东就越少。\n差异性可以算做是二次信息，是把事物的原本信息（一次信息）经过加工（对比）后得出的。',
      '\n',
      char(10)
    ),
    'public',
    '2005-05-15T03:58:49Z'
  );

