    NULL,
    replace (
      '二次信息?\n那第一次信息叫什么呢？怎么就叫了信息呢？我觉得判断一个事件（姑且用这个词来代替信息和不是信息的总体）是否是信息是一个过程，在这过程中就是利用了对比或者一些其他手段来确认信息的，也就是信息是判断以后才出现的，而不是从一开始就是信息。\n😜 说得有些绕。',
      '\n',
      char(10)
    ),
    'public',
    '2005-05-15T05:24:12Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    320,
    225,
    '133',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '221.233.212.31',
    NULL,
    replace (
      '哎~\n信息的定义分狭义和广义两种的\n狭义：主体感受到或表达的事物存在的方式和运动状态\n广义：事物存在的方式和运动状态\n信息是事物本来就有的一种属性，就象水是无色透明的这些物理属性一样，他并不因为我们人感觉得到还是感觉不到而存在不存在，他是一种客观存在！\n但是因为我们现在研究的水平有限，不可能把所有信息都研究了，所以只研究狭义定义中的信息\n你明白了吗？',
      '\n',
      char(10)
    ),
    'public',
    '2005-05-15T09:18:52Z'
  );

