VALUES
  (
    338,
    1851,
    '140',
    NULL,
    0,
    'babylon',
    '',
    NULL,
    '221.221.168.253',
    NULL,
    replace (
      'PS:我承认我片面的说了UI只是图形界面设计，OK~但是我不相信，你们的认识可以超越图形界面设计！\n作者这句话明显带有赌气成分，UI全称USER INTERFACE，翻译过来叫用户界面，或者人机界面，UI包含3个部分的内容，GUI（图形用户界面），交互设计（人机交互部分，负责操作流程等方面的设计，需要考虑多方面因素，用户使用习惯，知识层次，使用心理，所处环境等等），用户体验设计（检验设计的合理性，易用性等等，相当于软件开发的测试工程师了）。',
      '\n',
      char(10)
    ),
    'public',
    '2006-03-22T14:32:46Z'
  );

