INSERT INTO
  "comments"
VALUES
  (
    1092,
    948,
    '277',
    NULL,
    0,
    'ezard',
    '',
    NULL,
    '60.32.92.30',
    NULL,
    replace (
      'Wikipedia:狀況回報\n维基百科，自由的百科全书\n一些继续使用维基的方法\n使用其它维基服务器\n维基一共有四组服务器，分别位于韩国、佛罗里达、阿姆斯特丹和巴黎。一般从中国来的用户链接到韩国的服务器上。目前似乎韩国和佛罗里达的服务器被封了。巴黎和阿姆斯特丹的没有被封。但假如用的人多了的话不保证将来不会被封。用这两个服务器的方法是：\n在浏览器的代理设置里尝试使用下列代理服务器中的一个：\n207.142.131.205:80\n211.115.107.142:80\n145.97.39.132:80\n\------------------------------------',
      '\n',
      char(10)
    ),
    'public',
    '2005-10-27T18:21:10Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    1093,
    949,
    '277',
    NULL,
    0,
    'ezard',
    '',
    NULL,
    '60.32.92.30',
    NULL,
    replace (
      'Tor\ntor的网站：[http://tor.eff.org](http://tor.eff.org)\nPrivoxy的网站：[http://www.privoxy.org/](http://www.privoxy.org/)\n安装tor。tor目前提供win32、linux、bsd等平台的版本。\n安装Privoxy。Privoxy目前也是提供了win32、linux、bsd等平台的版本.\n启动tor\n启动Privoxy\n在Privoxy-Option-Edit main configration，在最顶上加上这条： forward-socks4a / localhost:9050 .（可别忘了那个 “.”）\n然后在浏览器里边将代理地址写成： localhost:8118\nDebian下的安装\n因为tor、privoxy是自由软件，有准备好的deb包，所以直接apt-get install tor privoxy安装即可。\n中國以外的用戶亦可以安裝 Tor 以協助提升 Tor 網路通信速度和品質。方法完全一樣，只需要按照上方所述設定即可。更多細節和高階配置請參閱詳細文檔\n另有Windows下免安装版本Tor, 感谢User:Luckygod提供。\n[http://spaces.msn.com/members/luckygod/Blog/cns!1ppJ9Wd\_q1PZJw1xgbFI0GDQ!771.entry](http://spaces.msn.com/members/luckygod/Blog/cns!1ppJ9Wd_q1PZJw1xgbFI0GDQ!771.entry)\n\------------------------------------',
      '\n',
      char(10)
    ),
    'public',
    '2005-10-27T18:21:30Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    1094,
    950,
    '277',
    NULL,
    0,
    'ezard',
    '',
    NULL,
    '60.32.92.30',
    NULL,
    replace (
      'TouchNet Browser\nTouchNet Browser较适合对代理服务器或者Tor配置感到困难，或者不想使Google Secure Access改变整个计算机的网络连接状态的情况。TouchNet Browser设置代理服务器后，并不改变其他网络应用软件的代理服务器设置。因此也适合想同时通过代理服务器访问維基百科，并直接连接使用其他网络应用的用户。\n英文版下载地址：[http://www.skycn.com/soft/8155.html](http://www.skycn.com/soft/8155.html)\n汉化版下载地址：[http://act.it.sohu.com/download/show-8917.html](http://act.it.sohu.com/download/show-8917.html)\n安装TouchNet Browser，适合于Windows 95/98/2000/XP系统，对Windows NT/2003支持情况不明。\n启动TouchNet Browser(以下描述以汉化版本为例)，点击菜单“工具”-“多代理服务器”-“更新代理服务器列表…”，稍后就可以在该菜单下看到若干代理服务器。\n在菜单“工具”-“多代理服务器”下点击其中一个地址，然后尝试访问維基百科，如果不能请另选其他。经测试，其中有若干可以访问維基百科的代理服务器。',
      '\n',
      char(10)
    ),
    'public',
    '2005-10-27T18:21:43Z'
  );

