INSERT INTO
  "comments"
VALUES
  (
    1118,
    963,
    '282',
    NULL,
    0,
    'guest',
    '',
    NULL,
    '219.236.16.181',
    NULL,
    replace (
      '不太谨慎地建议一下，s5s5的简历没有突出个人职业发展的意向。虽然不是cover letter，但是你有什么对个人和职业的计划，写在这种开放的简历上会比较给人信心。比如如果你希望在网页制作上加强自己，还是希望在程序制作上加强？职业本身也将是一种锻炼机会，如果你有一个不错的机会，将会如何改进自己？如果你有一个不太好的机会，你还愿意不愿意努力改变自己来争取更多发展？可能路过你的网站的陌生人只能花两分钟看一遍你的简历，而目前所包括的内容似乎缺少了一些鼓舞人心的东西。虽然了解你的朋友会知道你是实事求是地写自己的经历，但是不了解的人，也无法从你的简历中了解更多应该知道的东西。\n祝你找到理想的职业。 🙂',
      '\n',
      char(10)
    ),
    'public',
    '2005-10-29T04:40:18Z'
  );

