INSERT INTO
  "comments"
VALUES
  (
    2093,
    1903,
    '400',
    NULL,
    0,
    'Lenvo',
    '',
    NULL,
    '221.227.178.97',
    NULL,
    replace (
      '……\n大约一星期前在团结湖那个KFC门前，我刚走出那家网吧，迎面来了一对夫妇，五十岁上下，穿的虽然旧样子也很老，但还算整齐吧。问我清华大学怎么走。不待我说明乘车路线和方向，他又说到他们从山东老家来北京找在清华上学的儿子没找到，因为用光了钱已经两天没吃东西了。\n……\n我把那六元钱——一张新版的五元的和一张旧版的一元的，递给了他们，在旁人异样的眼神中匆匆逃离。那个时候我甚至没有听到他们说的“谢谢”，当然没有时间去体会被欺骗的感觉和谢谢声之外的那句隐隐的“又一个傻B”。\n……\n又是那一对夫妇，连衣服都没有换，这次问的不是清华了，这次问建国门怎么走。兜里有钱，我都准备掏钱了，还没有想起，不远的几天前在不远的团结湖我遇到过他们了。……\n这个是我在一篇文章中写到的我遇到的真实的事情。遇到类似的事情有太多太多。后来我看到网上有个办法，便采用了。遇到要钱的请他吃饭方便面面包之类的，遇到要吃的给他些钱，不要太多。我相信，这个社会还是有真的乞丐的，因为我曾经不是乞丐也像个乞丐。\n有兴趣的朋友去我的小站看看全文\n[http://www.lenvo.cn/post/36.html](http://www.lenvo.cn/post/36.html)\n有广告嫌疑，如果随随介意，请编辑一下或者删除。',
      '\n',
      char(10)
    ),
    'public',
    '2006-03-27T12:37:15Z'
  );

