INSERT INTO
  "comments"
VALUES
  (
    2325,
    2141,
    '421',
    NULL,
    0,
    'caoyusheng2005',
    '',
    NULL,
    '222.136.197.236',
    NULL,
    replace (
      '知道你的blog是在flickr上，挺喜欢看你的博客。但此篇却带有明显的情绪化。胡主席说了微软是朋友，这又何妨？一个人或国家可以有很多朋友，微软和谷歌都可以是我们的朋友，实际上我们都在使用这两家公司的产品，这并没有什么冲突，李开复离开微软加入谷歌后，不是自称自己的公关做得好了。胡主席还要访问波音，或许他还会说波音是中国的朋友，但这并不代表就向波音看齐了，空中客车我们就不买了，这个逻辑不对。再说，胡主席作为一个客人受到招待，出于礼貌说几句客气话是很正常的，外国人到中国也常夸咱，这恐怕很多也是出于礼貌。\n网络言论中情绪化的东西居多，理性的偏少。这或许是情绪化的东西更能引起共鸣，更能吸引眼球，但是理性和符合逻辑的言论才能真正体现水平，虽然关注度小了。',
      '\n',
      char(10)
    ),
    'public',
    '2006-04-21T13:36:37Z'
  );

