INSERT INTO
  "comments"
VALUES
  (
    2470,
    2494,
    '440',
    NULL,
    0,
    'netwjx',
    '',
    NULL,
    '222.90.159.194',
    NULL,
    replace (
      '从你后来发的一个贴找到这里的\n想不到你真拿Google Trends和百度指数 做比较\n如果说抄袭，这个谁也谈不上抄袭，统计这样的事谁都知道，只要有基础数据就可以作\n无论baidu google谁作都没什么，因为统计这样的事之前很多\n但是重要的是他们各自作的如何\nbaidu提供的就是关键字搜索量及这个搜索量的相对变化(最近的)，其它的...\ngoogle提供的大家就自己看了，图表不说了(内容包含的很多)，对应在某个时间发生的什么新闻事件，城市(似乎只有一部分城市)，地区，语言，这些影响确实很大的\n还有个比较另人觉得奇怪的\nbaidu提供同类信息的top榜，数字十分详细，优点不说了(我不喜欢凑热闹 况且那些top多不是我关注的 所以我没办法说优点)，缺点就是容易被有些人作弊，专门针对程序而写程序(这是所有真正喜欢使用互联网的人不愿意看到的)\ngoogle则不出什么top榜，让用户自己想，而且图表上只有曲线图，而没有数字，而图表中的新闻参考量(News reference volume)则不是仅仅依靠短期内的机器搜索可以改变的\n这么看并不能说google抄袭baidu的指数，但是之前baidu抄袭google的也就太容易让人看明白了，比如节日logo，明显感觉baidu不是完全自愿的(不知道google group和baidu贴吧那个早，但是bbs肯定比它们都早)\n个人对baidu指数不爽的，它明显有支持某些人作关键字站点(没价值的 或者狂使用无关关键字骗人的)的嫌疑(当然这个和搜索引擎的目的有冲突 但是会对baidu有些好处 之前baidu作过不少次对搜索引擎根本有冲突的事 还不是照样继续 只是被不少人骂而已 脸皮厚这招算是合格)，因为他提供整体上的top，再加上baidu的收录方法是什么站点都要，那么他必然是全球拥有最大中文网页收录量的baidu\ngoogle的则更象玩具，看看Examples(coffee, tea|colour, color)',
      '\n',
      char(10)
    ),
    'public',
    '2006-06-13T17:48:40Z'
  );

