INSERT INTO
  "comments"
VALUES
  (
    2497,
    2314,
    '442',
    NULL,
    0,
    '淫听羽息',
    '',
    NULL,
    '222.20.216.76',
    NULL,
    replace (
      '商业发展需要环境。漫骂不能改变任何事情。我本身是使用了百度指数与googletrends两个服务的，并没有发觉两者有很大的累同。更何况，如果说抄袭的话，web搜索技术貌似google发明的吧？我们能否依时间上的先后而判断说百度，yahoo等等都抄袭了google呢？抄袭这个词慎用吧。\n消费者不是上帝。消费者需要与生产者联合才能创造商业环境，没有好的消费者，也没有好的生产者。所以我们看，有需要滥交的人存在，就有色情市场的存在，有浮躁的消费者存在，生产者就不可能踏实。\n理智中肯的消费者培育品牌。品牌培育良好的市场，市场为消费者服务。品牌的打造离不开消费者。\n百度好不好？好。中文搜索都用它。但是品牌调查显示，它不是品牌。为什么？品牌不是商品好，品牌是生产者与消费者之间的情感依赖，是在公众心中的形象。正如妓院的商品好但是永远不会有人把妓院当成品牌，永远不会有人尊重妓院一样。\n好企业不单生产好产品，要生产好形象，好人格，好感情。\n[http://www.56kg.com](http://www.56kg.com)',
      '\n',
      char(10)
    ),
    'public',
    '2006-05-16T09:31:38Z'
  );

