INSERT INTO
  "comments"
VALUES
  (
    2599,
    2409,
    '457',
    NULL,
    0,
    'hung',
    '',
    NULL,
    '220.234.0.214',
    NULL,
    '本来就对盗版软件没什么好感，至于迅雷，实在没什么话说。可能在技术层面上讲，对于用户的侵犯尤甚于对于下载站点的利益损害，不过大部分用户并不会看到“山那边”的情况，只是觉得下载速度快、方便就可以了，就像为了不想花时间跑出去吃饭而去叫外卖，而且让那个送外卖的自己开门在屋子里乱转、随便拿东西带走。看了这两天在网上的讨论，都只是说下载站为了保护自己的利益在炒作而已，都不想想自己的利益怎么被尊重和保护，所以有的时候都怪自己明白太多事情，看大部分人都是太愚蠢。至于P2P和ISP的网络环境，本来就是一个恶性循环，在基础带宽并没有长足进步的时候，越是想提高传输速度（比如下载），越会增加整个网络的负担。也许快比慢好，但是，是在规则和环境的允许下，如果什么都不想付出，只想索取，那人的劣根性迟早颠覆了这个网络世界。',
    'public',
    '2006-06-03T15:52:35Z'
  );

INSERT INTO
