    '2006-06-03T16:08:02Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    2601,
    2411,
    '457',
    NULL,
    0,
    'hung',
    '',
    NULL,
    '220.234.0.214',
    NULL,
    '阿米，你在国内呆的时间比我久，你该比我更清楚国内业界的这些噱头。说到底，信息高速路还是要扎根于基础ISP的基建，技术不用多说了，电信垄断这么多年，会给用户好果子吃？我在几个国家上网都没这么费力的，带宽都是上10/100M的且便宜得很，国内……嗬嗬，有线通是有限通，网通和电信双线都有排斥现象，上网费用又高的可以，GPRS没有付购钱，都不会有PS。另外一点，道路开得再多总会有饱和的，所以上海才会有每个月的拍照拍卖，用来控制街面上的车辆数量，上网的这一群已经开始淡忘了“收支”的概念，国内即便到了G级带宽的年代，依然会有现在这样的问题。不信？看时间证明好了。',
    'public',
    '2006-06-03T17:42:49Z'
  );

