INSERT INTO
  "comments"
VALUES
  (
    2612,
    2492,
    '457',
    NULL,
    0,
    'netwjx',
    '',
    NULL,
    '222.90.159.194',
    NULL,
    replace (
      's5s5 \[ 2006-06-03 14:48:52 \]\nP2P就是这样啊～\n无论怎么样，快比慢好～\n\----------------------------------------\n不是吧 你真是不懂 还是装傻，这要是叫p2p，那ftp search叫什么(它似乎就叫ftp search)，技术方面基本一样，只是ftp search是开放的，而迅雷自己换了个壳子(外加些免费赠送的广告)；迅雷用户不上传的，要上传了才能叫p2p，况且p2p不是简单的说下载人越多就越快，这要涉及到具体的分段下载算法，我看过bt的算法描述(结果是bt容易发生总是先下载文件结尾的内容-\_-...)\n我坚持认为，迅雷自己提供了几个稀有资源存档服务器，不然有些文件本来网络上就十分稀少，而且下载链接不稳定，那么迅雷只有自己提供服务器才能让大家觉得：迅雷就是比其它的下载软件好\n所以我坚持不用迅雷(除了软件垃圾 技术一般，还有运营方和某些人的关系实在不好说)，目前还是FlashGet，国内站点基本上都提供镜象服务器组信息，遇到国外站点，比如sf.net，就手工改一下镜象服务器组信息，速度不比迅雷慢\n附:FlashGet的URL共享服务器，以及打开了ftp search后访问的ftp search站点服务器，经常无响应，虽然我不愿意那么怀疑，但是这实在太不正常了(FlashGet作者不是傻子，这个功能是提高速度的很有效的方法，为何会让其不能使用?)，后面的话可以自由猜测，仅仅猜测...',
      '\n',
      char(10)
    ),
    'public',
    '2006-06-13T14:01:07Z'
  );

