INSERT INTO
  "comments"
VALUES
  (
    2784,
    2614,
    '491',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '220.231.22.157',
    NULL,
    replace (
      '就拿我来说吧～\n我发了一个贴子，然后有很多人回了，然后我会自我感觉我TMD的棒！可以说是一呼百应，极大的满足了我的成就心，或者说是虚荣心～\n然后呢，我长期的发贴，长期的有很多人回，哇赛，我真牛啊。看来我也算是有点名气了～\n哼哼～然后我就这么被大家捧着，有点了高高在上的良好感觉了～\n然后呢，我就很高兴的没事时回忆一下，虽然我在平常生活中和普通人一样，可是呢，你们这些普通人发一个贴子可以象我一样一呼百应么？\n忽然有一天，我被人在口头上攻击了，我很郁闷，我辛苦每天码这么字，每天尽力让大家爽我容易吗我？\n然后，我就要反击这种人，要找回一些失落的感情，然后我就在Blog攻击指责我的人了～\n这些都是我投入的感情～\n感情这种东东么，大家也都明白，这是一种感觉，说不清的，就如同谈恋爱一样～',
      '\n',
      char(10)
    ),
    'public',
    '2006-07-30T17:04:50Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    2785,
    2615,
    '491',
    NULL,
    0,
    'hung',
    '',
    NULL,
    '220.234.0.214',
    NULL,
    replace (
      '呵呵，米老鼠看的人还是太少了，我认识不少人，都很少把这类事情看重的。起码生活中能生存下来，才能谈别的，有了足够的生活基础，才能享受生活。多去计较这些事情不如实际的赚钱、享受生活去，blog 本身是一种余兴活动，网络不过是一个工具，娱乐的人娱乐，赚钱的人赚钱。\n因为息乐园的流量这么大，所以我因此接触的国内网络里的人不会比幻灭的少，从来也没遇到过这类事情，这该说明一些事情了吧？而且其中还有不少本来就对我的直言不讳很有意见的一群人，到最后也是可以达成理解，和谐交流的。个人以为，幻灭本身的心态有些问题。',
      '\n',
      char(10)
    ),
    'public',
    '2006-07-30T17:04:50Z'
  );

