INSERT INTO
  "comments"
VALUES
  (
    3244,
    3068,
    '564',
    NULL,
    0,
    'HUNG',
    '',
    NULL,
    '220.234.4.205',
    NULL,
    replace (
      '算了，米老鼠，物以类聚，中文 Blogosphere 大部分也就出这种东西，垃圾太多了，做清扫工作也就下岗了。\n中国式的言论生存无非就是历史经典的那一套，扣个大帽子，莫须有，无风起浪，再加一群哄客起哄，zola 这群人的伎俩比起宋朝那时候的秦某人，还是差很多了。\n所以别惹麻烦上身了，国内互联网这一块无非是一个浑水潭，越搅越黑，做实事的人不如玩炒作的人，老老实实的人不如卖丑恶搞的人。像 zola 那种没有工作吃喝还要靠可怜的父母的人就是有一点好处 ----- 不用担心没有下一顿饭，而且他背后还有一群稍稍“聪明”一点的人，拿着他这个白痴当“枪”使，它还浑然不觉，我、Icebin，包括之前的 Postshow 都还是属于在做着 Blog Network 的一群，看一下它的目标就知道了，自命清高还不是被利益驱使？看明白了就好，回头继续自己的 lifestyle，也没损失什么。\n而且你也别抬高它的价值了，一个连加拿大还是加州都分不清楚地生物，智力有限。还CW团队中人告密？嗬嗬，中文区一共才四个人，一个休假不上网，一个我生活里的朋友，另一个都在避开这些纠纷，真不知道它是真傻还是假傻，随他去了。',
      '\n',
      char(10)
    ),
    'public',
    '2006-12-09T22:36:55Z'
  );

