INSERT INTO
  "comments"
VALUES
  (
    3460,
    3333,
    '593',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '220.231.22.157',
    NULL,
    replace (
      '这个是SEO方面的东东了，PR值是GOOGLE给每个网页的打分，分越高在搜索结果中显示的位置越高～\n他的算法主要有两二方面原因，一个是外链数，就是别人链接你的数，还有链接你的这个网页的PR值～\n还有一个是你自己所写的内容是不是人无我有，或者同一种内容，你比别人出现的早，长期这样积累就会有一个比较好的PR值了，呵呵～\n那个文章中说的中文PR值比较低应该是GOOGLE对中文分词技术还不太完美吧，所以不敢给太高的PR，太高的话在中文分词还不完美的情况下很容易被人作弊，国外的英文就没有分词这个技术障碍，所以PR高～ 😂',
      '\n',
      char(10)
    ),
    'public',
    '2007-03-23T09:11:47Z'
  );

