VALUES
  (
    3513,
    3374,
    '598',
    NULL,
    0,
    'never_online',
    '',
    NULL,
    '124.226.117.8',
    NULL,
    '感觉MS现在是没有新鲜的创意和点子了，包括vista在内的产品几乎都是老路线，很多产品都是为了与其它的对手分一杯羹，也包括.net。虽然他俱有强大的技术支持与用户群体，但与其这样，还不如自己创建一套新的产品，这样更能吸引我们开发者与用户。再按这样的方案走下去，最后的受害者不仅仅是MS，borland就是很典型的例子。 🙂',
    'public',
    '2007-04-16T18:34:29Z'
  );

