INSERT INTO
  "comments"
VALUES
  (
    3641,
    3644,
    '620',
    NULL,
    0,
    'netwjx',
    '',
    NULL,
    '219.145.254.175',
    NULL,
    replace (
      '这些  其实  没有从本质的解决问题\n我觉得 桌面应该有一个布局策略实现  用户可以自行使用其它的布局实现\n图标大小也是可以调整的,并且建议多使用矢量图标   在一个布局块中的图标大小布局也是有策略\n布局策略实现和 图标布局策略(包括图标排序的策略) 都可以用户自行下载,或者提供方便的工具快速下载设置,类似linux下的软件包管理\n现在我不喜欢在桌面放太多图标,因为我经常放临时文件到桌面,太多图标不容易找,并且按照使用率,只有很少一部分经常使用,所以桌面只放几个(也常用 也不常用的)\n如果自己排列图标,不小心重新排列就完蛋了\n这个东西实际是java python之类的语言 GUI库的布局设计规则.容器(可能是窗口 也可能是窗口中布局对象中的布局对象)大小改变时可以自动变动内部控件的大小\n其实web页也应该使用这样的设计准则,能减少大量重复内容的传输,不过html最初就是为瘦客户端实现而设计的,只是现在变得太肥了,不很合时宜了\n另Wow的UI设计的就很强悍,我是说整个体系,使用第3方插件可以十分自由的控制界面的内容,比如技能图标\n可惜操作系统的桌面图标不能照搬哪个,游戏的环境和操作系统的环境不一样(图标数量变化速率慢 图标位置较固定)',
      '\n',
      char(10)
    ),
    'public',
    '2007-10-05T21:02:18Z'
  );

