INSERT INTO
  "comments"
VALUES
  (
    3737,
    3654,
    '633',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '218.18.91.109',
    NULL,
    replace (
      '上网其实主要是你找的SB文件要对啊~\n删除浏览器后，然后导入SB文件~\n然后再装浏览器\n接入点设为空\n然后再用QQ登陆激活\n再把接入点设为CMNET\n用浏览器登陆\n再氢接入点设为CMWAP就好了\n你再装不了浏览器可能是相应的电脑软件没搞好啊~\n你试试这个~\nDesktop Manager 4.2.2b020.zip\n[http://dualband.three.com.hk/website/image/business/blackberry/Desktop%20Manager%204.2.2b020.zip](http://dualband.three.com.hk/website/image/business/blackberry/Desktop%20Manager%204.2.2b020.zip)',
      '\n',
      char(10)
    ),
    'public',
    '2007-10-11T21:00:48Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    3738,
    3655,
    '633',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '218.18.91.109',
    NULL,
    replace (
      '7290C\_PBr4\[1\].1.0\_rel556\_PL1.8.0.154\_A4.1.0.377\_Taiwan\_Mobile.rar\n[http://down.maxpda.com/download/software-523.html](http://down.maxpda.com/download/software-523.html)\n还有这个最新版的ROM，也要装上',
      '\n',
      char(10)
    ),
    'public',
    '2007-10-11T21:02:22Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    3739,
    3656,
    '633',
    NULL,
    0,
    's5s5',
    's5s5cn@gmail.com',
    'https://s5s5.me',
    '218.18.91.109',
    NULL,
    replace (
      '1.安装桌面管理器(默认路径安装)  \n2.安装机器对应的rom版本(默认路径安装)  \n3.如需刷机的话,改文件名C:Program FilesCommon FilesResearch In MotionAppLoaderVendor.xml,这个文件随便改个文件名就可以  \n4.黑莓连接电脑,如出现什么密码设定的提示不要管他,取消就可以  \n上网设置:确保SIM卡同时开通CMNET和CMWAP  \n1.下载网络上的serverbook  \n2.删除掉机器自带的浏览器  \n3.恢复网络上下载的serverbook到黑莓  \n4.重新安装机器自带的浏览器,看股票的话同时安装JAVA,可同时安装QQ(激活上网必需)及其它你自己需要的软件游戏  \n5.进入机器选项->高级选项->服务预定(serverbook),按下滚轮键【反删除】不是删除哦 到不能反删除为止\n6.进选项->TCP->APN,确保此项为空  \n7.进选项->防火墙->按下滚轮选择复位设置,保存后退出  \n7.进入qq随便填号码和密码,登陆,对出现的防火墙选项全部打勾并允许连接,等到提示出现网络信号不好,稍后重试为止,并退出QQ  \n8.进选项->TCP->APN,填入cmnet  \n9.进机器自带的浏览器,登陆主页看见网页内容出现即可退出\n10.进入机器选项->高级选项->服务预定(serverbook),删除IPPP项  \n11.进选项->TCP->APN,填入cmwap 保存退出  \n至此可以成功上网!!!',
      '\n',
      char(10)
    ),
    'public',
    '2007-10-11T21:03:53Z'
  );

