INSERT INTO
  "comments"
VALUES
  (
    3824,
    3754,
    '664',
    NULL,
    0,
    '秀才',
    '',
    NULL,
    '221.221.237.100',
    NULL,
    replace (
      '在我的眼中，但凡著名的艺术家在早期都是穷困潦倒的，我国香港特别行政区的著名摄影艺术家陈冠希老师更是如此，陈老师早年拍摄摄影作品的时候，连一台像样的专业相机都没有，可他硬是用一部普通的拍照手机就拍出了近2000张震撼人心、享誉全球的摄影名作，且不说后无来者，恐怕前无古人这样的称号对于陈冠希老师来说是当之无愧了!\n　　细观陈老师的作品，尤其是不朽名作“阿娇之媚”，在简陋而温馨的环境下，影像中人物表情彷徨、迷离，眼神里流露出对现实生活的不惑而又执着的探寻幸福的真正意义，颇有日本著名摄影师西川和久（NishikawaKazuhisa）摄影风格的神韵。纪实主义朴素风格拍摄的作品正是弱势群体艰辛生活的真实写照，陈冠希老师硬是用他简陋的摄影器材：手机!记录下了那一个个不朽的历史瞬间。\n　　陈老师的经典之作“柏芝制服”系列可以看作是他由纪实主义手法向时尚表现主义转型的试验性作品，这部作品拍摄手法新颖，技巧运用娴熟，对人物服装的把握更是达到了炉火纯青的地步，我们不难看出这部作品深受西方时尚摄影鼻祖——GuyBourdin的影响，冠希老师正是通过这一系列的作品完美地将时尚表现主义中人物的自我展现欲呈现在大家的眼前。\n　　勤奋的冠希大师拍了诸多惊艳的照片，但他从不炫耀这些，也从不以这些作为扬名立万的资本，他默默无闻的屈就于香港那鱼龙混杂的商业环境下作艺人谋生。这是时代的悲哀!这是艺术界的巨大损失!!幸运的是，陈冠希大师的作品尘封了数年之后，终于在一次偶然的机会下展现在了世人面前!并迅速以几何级数般的速度在全球传播开来。由此我们不难看出，不仅陈冠希大师的摄影艺术作品是完美的、震撼的，这世上热爱艺术、热爱摄影的人们对不朽摄影名作的追求也是疯狂和永无止境的，并且还一传十、十传百的感染着无数的普通人，使他们也纷纷踏入到了摄影艺术的伟大殿堂中。\n转',
      '\n',
      char(10)
    ),
    'public',
    '2008-02-22T11:56:30Z'
  );

