INSERT INTO
  "comments"
VALUES
  (
    3875,
    4015,
    '676',
    NULL,
    0,
    'JasonKing',
    '',
    NULL,
    '125.83.58.193',
    NULL,
    replace (
      'Ctrl+Space 并不是Dreamweaver切换代码提示的快捷键，这个可能算是个小BUG吧，很早就发现了，你可以把输入法热键改一下就知道了。\n关于这个小BUG，其实很好解决，你不用关闭页面再重新打开的，假如你发现提示功能已经无效了，你只要打开输入法，随便打个字，再关闭输入法就可以了。以极点五笔为例，它的中英文输入切换热键是右SHIFT键，打完汉字不用关键输入法，点一下右SHIFT继续写代码就可以了。\n其实用DW写代码，最最好用的就是他的代码片断功能，如果你在用的话，你会知道它对写代码的效率提升，至少有100%以上。\nCS4有些新功能确实不错，但有几个小细节觉得反而画蛇添足了。个人觉得要同时修改很多不同的页面的话，CS4比较不错，但如果是针对单一页面来修正浏览器兼容性问题，CS3效率要高些。',
      '\n',
      char(10)
    ),
    'public',
    '2008-10-29T22:03:37Z'
  );

