INSERT INTO
  "comments"
VALUES
  (
    4021,
    3970,
    '782',
    NULL,
    0,
    '子鼠',
    '',
    NULL,
    '121.76.228.199',
    NULL,
    replace (
      '![引用来自 linxz](/assets/images/quote.gif) 引用来自 linxz\n\n引用内容\n另外，现在别扯太深的语义！现在很多的标签不同浏览器中的解释是不一样的，语义化的结构谁都知道非常好，非常的合理；但为了这些标签我们可以要写很多的代码，从维护方面来说，不是一个很好的解决方案。  个人认为当前阶段，只有去写适合的代码，而不是完全标准的代码，但心里要清楚，将来的方向是什么！\n不赞同你这个看法，如果现在连根本的基础都没掌握好，以后怎么做呢。\n如果你要方便那直接用PS切图导出页面多方便啊。\n还有刚刚你也提到一个说三列的hack多，呃，不好意思，到目前位置我还未发现我用很多hack，用得最多的却是在对ie的定位（bottom），以及margin等问题上。\n\n每个网站都有自已适应的一种写法，考虑的因素有很多，例如：多人开发、后期维护等，网站的代码不可能是一个人在写；在实现一些效果时，为了标准等因素，代码有时会过于复杂； 你好好看一下我的观点，是写“适合的代码”，如果一个FW图片直接输出，是当前这件事非常适合的解决方案，那没有什么不好的。  代码有用户群，有生命周期，在有限的时间内，给有限的用户群，提供最小成本的代码，我认为是很好的解决方案。  如果没有这些考虑，我可能会把一些页面写的非常的标准，但我花的时间是成本呀？ 值吗？　\n一行三列的效果我几年前就写过，如果不考虑IE6以下，当然不用HACK了；  再说个较麻烦的例子，图片水平垂直居中，你不用表格能累死你，值吗？  你不信，你写一写！',
      '\n',
      char(10)
    ),
    'public',
    '2008-09-07T19:17:29Z'
  );

