INSERT INTO
  "comments"
VALUES
  (
    4030,
    3986,
    '782',
    NULL,
    0,
    'Amilim',
    '',
    NULL,
    '116.235.216.180',
    NULL,
    replace (
      '对于FLOAT浮动，看了这么多大家的讨论 似乎战战兢兢的\n我们无法否认的是 div + float  比 table 单纯从页面布局和打开速度 都来得优秀\n因为是闭合浮动的原因 而说这不适合初学者\n我看后 忍不住笑了起来\n我是不是可以这么理解\n初学者们 CSS 很难 Div 很不容易掌握 你们不要学了\n当然我并不提倡为了div 而div，但是如果说你们现在为了一点点的所谓的难度和不易掌握而table 的话\n那只能是一种悲哀\nOK\n我的意见是\n你们应该说\n初学者们 float 不易掌握 下面的文章或分析 是我对float 的理解 希望看了对你们有帮助\n在css study 路上 破荆前进',
      '\n',
      char(10)
    ),
    'public',
    '2008-10-03T09:57:42Z'
  );

INSERT INTO
  "comments"
VALUES
  (
    4031,
    3987,
    '782',
    NULL,
    0,
    'Evance',
    '',
    NULL,
    '121.0.29.225',
    NULL,
    replace (
      '实在看不过去了。\n冒一个泡。\n1.现在这一个时代了，基于web标准的xhtml规范开发页面的优点还把节省带宽拿出来说事。我承认它的优越性，但是这个几乎可以忽略不计的优点拿出来说服意见相反者，没有什么可能性。\n2.\n\n![引用内容](/assets/images/quote.gif) 引用内容\n\n一个兼容所有浏览器的一行三列自适应的布局，用简单的代码就能实现，为什么要用更多的HACK 或代码来实现呢？\n\n这一个可真把我雷到了，等到大量数据的时候，维护的时候才叫一个麻烦呢。\n子鼠说的效率单是考虑了开发阶段的成本，那维护时候呢？\n说实话，对于一个熟手来说，基于division结构和table结构的布局在开发的情况下，几乎没有什么区别..\n3.CSS的选择符深度这一个问题，很明显，子鼠只是通过臆想　-　我不是人身攻击。\n我叫我拿证据出来也拿不出来，但是熟悉xml工作机制的话，自然会相信米随随的结论是正确的。\n4.\n\n![引用内容](/assets/images/quote.gif) 引用内容\n\n不要去使用生僻的标签，因为这些标签往往在不同浏览器中解释出来的效果不一样；\n\n这一个结论，真是足以让一个前端工作者心寒，彻底雷到了..\n举例说<address />相对生僻，但是用样式表可以控制的，为啥不用，就因为不同的浏览器默认的解释不一样就不用了？\n5.最后说一下，米随随为啥不换一下字体大小，我看得好累。\n\n![引用来自 s5s5](/assets/images/icon_reply.gif) s5s5 于 2008-10-12 01:15 AM 回复\n\n嘿嘿，换啦换啦，这不半夜来换掉了，HOHO~',
      '\n',
      char(10)
    ),
    'public',
    '2008-10-04T21:20:26Z'
  );

