INSERT INTO
  "comments"
VALUES
  (
    4090,
    4117,
    '1416',
    NULL,
    0,
    'Young',
    'essentialblog@gmail.com',
    'http://www.essentialblog.cn/',
    '121.33.126.176',
    NULL,
    replace (
      '中文 WordPress 工具箱——这个真的不错，我一直在用。\n\nSamsarin PHP Widget——没有用过，不过有用Exec-PHP，可以在页面执行PHP。\n\nAkismet——必备的。\n\nAll in One SEO Pack－－用ing\n\nAudio player--我的博客追求的是无声胜有声。\n\nCustom Smilies－－有空试试。\n\nExternal Links－－读者自由选择爱到哪就到哪，窗口在哪里打开都一样。\n\nGoogle Analyticator－－我是直接到google去看的。\n\nGoogle XML Sitemaps－－很好用。\n\nSearch Everything－－我用google自定义搜索\n\nWordpress Thread Comment－－我用Subscribe to Comments\n\nWordPress Tweaks－－没有用过，不过准备试试。\n\nWordPress UE－－之前雪山飞猪有用，现在不用了。\n\nWP-PageNavi--不错的插件。\n\nWP-PostViews－－或许我该试试。\n\nWP-PostViews Widget－－我觉得对外观有影响。\n\nWP-Syntax－－不怎么适合精博。\n\nWP-T-Wap－－我的手机没钱上网。',
      '\n',
      char(10)
    ),
    'public',
    '2008-11-09T08:15:26Z'
  );

